# ----------- Utilities -----------
def clean_text(text):
    return text.strip().lower().translate(str.maketrans('', '', string.punctuation))

def translate(text, src='auto', target='en'):
    try:
        return GoogleTranslator(source=src, target=target).translate(text)
    except Exception:
        return text

def is_hindi_text(text):
    if any('\u0900' <= c <= '\u097F' for c in text):
        return True
    roman_hindi_keywords = ["namaste", "kaise", "ho", "kya", "tum"]
    return any(word in text.lower() for word in roman_hindi_keywords)

