LOCAL_QA = {clean_text(qa["question"]): qa["answer"] for qa in LOCAL_QA_RAW}

# Embedding model
embedding_model = SentenceTransformer('paraphrase-MiniLM-L6-v2')
LOCAL_QA_QUESTIONS = list(LOCAL_QA.keys())
LOCAL_QA_EMBEDDINGS = embedding_model.encode(LOCAL_QA_QUESTIONS, convert_to_tensor=True)

# ----------- Neo4j Setup -----------
driver_instance = neo4j_conn.Neo4jConnection()
neo4j_available = driver_instance.driver is not None

# ----------- Generate Response -----------
def generate_response(user_question):
    output_lang = 'hi' if is_hindi_text(user_question) else 'en'
    english_question = translate(user_question, src='auto', target='en')
    clean_question_text = clean_text(english_question)
    final_answer = None

    # Step 1: Neo4j query
    if neo4j_available:
        try:
            result = driver_instance.run_query(
                "MATCH (n:QA {question: $q}) RETURN n.answer AS answer",
                {"q": clean_question_text}
            )
            record = result.single() if result else None
            if record and record.get("answer"):
                final_answer = record["answer"]
        except Exception:
            final_answer = None

    # Step 2: Local QA semantic search
    if not final_answer:
        user_embedding = embedding_model.encode(clean_question_text, convert_to_tensor=True)
        cos_scores = util.pytorch_cos_sim(user_embedding, LOCAL_QA_EMBEDDINGS)
        best_idx = cos_scores.argmax()
        best_score = cos_scores[0][best_idx].item()
        if best_score > 0.65:
            final_answer = LOCAL_QA[LOCAL_QA_QUESTIONS[best_idx]]
        else:
            final_answer = "Sorry, I don't know the answer."

    # Step 3: Translate to Hindi if needed
    if output_lang == 'hi':
        final_answer = translate(final_answer, src='en', target='hi')

    return final_answer